INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】特異な力で変質したクリーパー。\n無数のトゲを持つ蔓を巻き付け、動きを奪う。\n\n・バトル開始時、自身の物理防御力と魔法防御力\n　を小アップさせる。この防御力アップ効果で上\n　昇した防御力は、バトル中に受ける防御力ダウ\n　ンスキルの影響を受けない。\n・ニードルクリーパーから受けるすべてのダメー\n　ジで発生する、パーティキャラのＴＰ回復量を\n　中ダウンさせる。\n・ユニオンバーストは、最も近い敵２キャラに物\n　理大ダメージを与え、拘束状態を付与し、ＴＰ\n　を大ダウンさせる。このスキルの状態異常はダ\n　メージを無効化しても付与される。\n・最も近い敵３キャラの物理防御力を大ダウンさ\n　せ、毒状態を付与する。このスキルにより付与\n　された毒のダメージでは、ＴＰが回復しない。", 105790401);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】大きな皮翼を使い、空を駆ける翼竜。\n巨大な火球を吐き、侵入者の行く手を阻む。\n\n・バトル開始時、自身の物理防御力と魔法防御力\n　を小アップさせる。この防御力アップ効果で上\n　昇した防御力は、バトル中に受ける防御力ダウ\n　ンスキルの影響を受けない。\n・ワイバーンから受けるすべてのダメージで発生\n　する、パーティキャラのＴＰ回復量を中ダウン\n　させる。\n・ユニオンバーストは、最も近い敵を中心にした\n　広範囲の最大３キャラに物理大ダメージを与え、\n　物理防御力を中ダウンさせる。さらに自身の物\n　理防御力をバトル終了まで小アップさせる。こ\n　のスキルの状態異常はダメージを無効化しても\n　付与される。\n・最も近い敵３キャラをノックバックさせ、行動\n　速度を中ダウンさせる。", 105790601);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】強力な氷のブレスで前衛を一瞬で\n氷漬けにし、咬みついて身体を砕く獰猛な深海竜。\n\n・バトル開始時、自身の物理防御力と魔法防御力\n　を小アップさせる。この防御力アップ効果で上\n　昇した防御力は、バトル中に受ける防御力ダウ\n　ンスキルの影響を受けない。\n・シードレイクから受けるすべてのダメージで発\n　生する、パーティキャラのＴＰ回復量を中ダウ\n　ンさせる。\n・ユニオンバーストは、召喚体、分身を除いた最\n　も近い敵３キャラに物理特大ダメージを与え、\n　さらに物理防御力と魔法防御力を特大ダウンさ\n　せる。このスキルの状態異常はダメージを無効\n　化しても付与される。\n・召喚体、分身を除いた最も近い敵２キャラに魔\n　法大ダメージを与え、短時間凍結状態を付与す\n　る。敵キャラのＨＰが70％未満の場合、長時\n　間凍結状態を付与する。このスキルの状態異常\n　はダメージを無効化しても付与される。", 105800101);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】人竜一体となって戦うゴブリン騎手。\n敏速に空を駆け巡り、地上の敵に襲いかかる。\n\n・バトル開始時、自身の物理防御力と魔法防御力\n　を小アップさせる。この防御力アップ効果で上\n　昇した防御力は、バトル中に受ける防御力ダウ\n　ンスキルの影響を受けない。\n・ゴブリンライダーから受けるすべてのダメージ\n　で発生する、パーティキャラのＴＰ回復量を特\n　大ダウンさせる。\n・ユニオンバーストは、召喚体、分身を除いた最\n　も遠い敵３キャラに物理大ダメージを与え、ス\n　タン状態を付与する。このスキルの状態異常は\n　ダメージを無効化しても付与される。\n・召喚体、分身を除いた最も遠い敵２キャラに物\n　理小ダメージを与え、物理防御力を大ダウンさ\n　せる。このスキルの効果はダメージを無効化し\n　ても付与される。\n・通常攻撃は、挑発を無視して最も遠い敵１キャ\n　ラに物理中ダメージを与える。このスキルによ\n　るダメージでは、ＴＰが回復しない。", 105800201);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】氷河地帯を支配する厳霜の魔狼。\n冷酷な仔らが標的を貫き、氷爪が獲物を引き裂く。\n\n・バトル開始時、自身の物理防御力と魔法防御力\n　を小アップさせる。この防御力アップ効果で上\n　昇した防御力は、バトル中に受ける防御力ダウ\n　ンスキルの影響を受けない。\n・フロストハウンドから受けるすべてのダメージ\n　で発生する、パーティキャラのＴＰ回復量を中\n　ダウンさせる。\n・ユニオンバーストは、召喚体、分身を除いた最\n　も近い敵３キャラに魔法特大ダメージを与え、\n　凍結状態を付与し、自身の魔法防御力をバトル\n　終了まで小アップさせる。このスキルの状態異\n　常はダメージを無効化しても付与される。\n・召喚体、分身を除いた最も近い敵３キャラに魔\n　法大ダメージを与え、魔法防御力を中ダウンさ\n　せる。このスキルの効果はダメージを無効化し\n　ても付与される。", 105800401);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】強者の魂を幽鬼とし従える、冥府の高官。\n亡者の念が刃に絡みつき、動きを鈍らせる。\n\n【特殊効果】\n・自身に物理／魔法防御力アップ（ダウン不可）\n・全スキルダメージＴＰ回復減少\n【ユニオンバースト】\n・前から１番目の敵と周囲に魔法割合ダメージ\n・自身の魔法攻撃力が高いほど：ダメージアップ\n・前から１番目の敵と周囲に最大ＨＰダウン\n　（必中）\n・与えた総ダメージが高いほど：ＨＰダウン量\n　アップ\n【スキル１】\n・前から１番目の敵と周囲に呪い（ＴＰ回復不可）\n・自身の魔法攻撃力が高いほど：ダメージアップ\n・前から１番目の敵と周囲にＨＰ回復量ダウン\n・前から１番目の敵と周囲にＨＰ吸収ダウン\n【通常攻撃】\n・前から敵１体に魔法割合ダメージ\n・自身の魔法攻撃力が高いほど：ダメージアップ", 105810101);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】武具に取り憑き、手足のように操る魔物。\n堅牢な装甲と巨大な魔剣で冒険者を苦しめる。\n\n【特殊効果】\n・自身に物理／魔法防御力アップ（ダウン不可）\n・自身にＴＰダウン無効\n・敵全体にＴＰ上昇ダウン\n・敵全体にＨＰ吸収ダウン\n【ユニオンバースト】\n・前から敵１体に魔法ダメージ\n・前から敵１体にスタン（必中）\n・自身に魔法攻撃力アップ\n・自身に物理防御力アップ\n【スキル１】\n・前から敵１体に魔法ダメージ\n・前から敵１体にスタン（必中）\n・前から敵１体にＨＰ回復量ダウン（必中）", 401904401);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】棄てられたモノの怨念より生まれた悪霊。\n怨む者の心臓を狙い定め、呪いの釘を打ち込む。\n\n【特殊効果】\n・飛行効果無視\n・自身に物理／魔法防御力アップ（ダウン不可）\n・自身にＴＰダウン無効\n・敵全体にＴＰ上昇ダウン\n・敵全体にＨＰ吸収ダウン\n【ユニオンバースト】\n・敵全体に魔法ダメージ\n・敵全体に物理／魔法攻撃力ダウン（必中）\n・敵全体にＨＰ回復量ダウン（必中）\n【スキル１】\n・敵全体に魔法ダメージ\n・敵全体に呪い（必中）\n・敵全体に束縛（必中）\n・最もＨＰ割合が低い敵のＨＰ割合が低いほど：\n　束縛時間アップ\n【スキル２】\n・物理か魔法攻撃力が最も高い敵１体に魔法ダ\n　メージ\n・物理か魔法攻撃力が最も高い敵１体に物理／\n　魔法与ダメージダウン、呪詛（必中）", 401904406);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】魔力を蓄え雷撃として放電する怪鳥。\n雷雲と共に顕現し、天災の如き雷で敵を葬り去る。\n\n【特殊効果】\n・自身に物理／魔法防御力アップ（ダウン不可）\n・自身にＴＰダウン無効\n・敵全体にＴＰ上昇ダウン\n・敵全体にＨＰ吸収ダウン\n【ユニオンバースト】\n・前から敵１体に魔法ダメージ\n・前から敵１体に麻痺（必中）\n・自身に魔法攻撃力アップ\n・自身に魔法防御力アップ\n【スキル１】\n・前から敵１体に魔法ダメージ\n・前から敵１体に麻痺（必中）\n・前から敵１体にＨＰ回復量ダウン（必中）", 401905401);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】尽き果てぬ動力で、命令を遂行する魔鎧。\n剛毅たる双肩は、領域を侵す者を拒み圧砕する。\n\n【特殊効果】\n・自身に物理／魔法防御力アップ（ダウン不可）\n・自身にＴＰダウンカット\n・自身にＴＰダウン上限\n・敵全体にＴＰ上昇ダウン\n・敵全体にＨＰ吸収ダウン\n【ユニオンバースト】\n・前から１番目の敵に物理ダメージ\n・前から１番目の敵と周囲に物理ダメージ\n・前から１番目の敵と周囲にスタン（必中）\n【スキル１】\n・前から１番目の敵と周囲に物理ダメージ", 401906403);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】秘術を用いて支配を目論む小鬼学者。\n禁忌の劇毒を創出し、全ての自由を強奪する。\n\n【特殊効果】\n・自身に物理／魔法防御力アップ（ダウン不可）\n・自身にＴＰダウンカット\n・敵全体にＴＰ上昇ダウン\n・敵全体にＨＰ吸収ダウン\n【ユニオンバースト】\n・敵全体にバリア解除\n・敵全体に魔法割合ダメージ\n・敵の数が少ないほど：ダメージアップ\n【スキル１】\n・敵全体に魔法ダメージ\n・物理攻撃をする敵全体に物攻ダウン（必中）\n・敵の数が少ないほど：ダウン量上昇\n・魔法攻撃をする敵全体に魔攻ダウン（必中）\n・敵の数が少ないほど：ダウン量上昇\n【スキル２】\n・前から敵２体に魔法ダメージ\n・前から敵２体に行動速度ダウン・猛毒（必中）", 401906407);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】豪快に戦斧を振るう熟練のゴブリン戦士。\n幼き戦士を脇に抱え、魂の技を見せ付ける。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から敵１体に物理ダメージ\n・自身に物理攻撃力アップ\n・自身に物理防御力アップ", 410010101);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】雷雲を従え、無邪気に暴れるカミナリ娘。\n油断すると、加減知らずの雷撃を見舞われる。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法ダメージ（飛行効果無視）\n【スキル１】\n・後ろから敵３体に魔法ダメージ", 410010201);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】無数の残骸で再構築された巨大ゴーレム。\n巨岩の腕を振り下ろし、地盤ごと敵を粉砕する。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理ダメージ\n・自身がバリア状態：ダメージアップ\n【スキル１】\n・自身に物理無効バリア\n・自身に魔法無効バリア\n【通常攻撃】\n・前から敵２体に物理ダメージ", 410010301);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】魔力の雨が集まり形を成した冷酷な水霊。\n吹き荒れる暴雨は、無慈悲に冒険者を飲み込む。\n\n【特殊効果】\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法ダメージ\n・敵全体にスタン（必中）\n・前方範囲ＨＰ70％未満：ノックバック（必中）\n・後方範囲ＨＰ70％未満：引き寄せ（必中）\n【スキル１】\n・後ろから敵１体に魔法ダメージ（挑発無視）\n・後ろから敵１体を引き寄せる（挑発無視・必中）\n・後ろから敵１体に行動速度ダウン（挑発無視・\n　必中）\n【通常攻撃】\n・前から１番目の敵と周囲に魔法ダメージ\n・前から１番目の敵と周囲に物理／魔法攻撃力ダ\n　ウン（必中）", 410010401);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】魔力を蓄え雷撃として放電する怪鳥。\n雷雲と共に顕現し、天災の如き雷で敵を葬り去る。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から敵１体に魔法ダメージ\n・前から敵１体に麻痺（必中）\n・自身に魔法攻撃力アップ\n・自身に魔法防御力アップ\n【スキル１】\n・前から敵１体に魔法ダメージ\n・前から敵１体に麻痺（必中）\n・前から敵１体にＨＰ回復量ダウン（必中）", 410010501);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】甲羅に大樹が根ざすほどの老大な陸ガメ。\n敵の攻撃を耐え続け、憤怒の反撃を見舞う。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理ダメージ\n・敵全体に物理／魔法クリダメダウン（必中）\n【スキル１】\n・自身に物理／魔法防御力アップ\n・敵全体に物理固定ダメージ（飛行効果無視）\n・自身の物理攻撃力が高いほど：ダメージアップ\n【全ターゲットブレイク時発動】\n・自身にクリティカル被ダメージアップ\n・自身にブレイク無効化", 410010601);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】特異な力で変質したサベージベア。\n怒りを込めた剛腕は、敵ごと地面を引き裂く。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から１番目の敵と周囲に物理ダメージ\n・前から１番目の敵と周囲にスタン（必中）\n【スキル１】\n・前から１番目の敵と周囲に物理ダメージ\n・前から１番目の敵と周囲に物理防御力ダウン\n　（必中）", 410010701);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】夢幻より生まれ、闇を彷徨う魔獣。\n悪夢の牢に獲物を縛り、旨そうに生気を喰う。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・物理か魔法攻撃力が最も高い敵１体にステータ\n　スアップ解除、魔法ダメージ\n・物理か魔法攻撃力が最も高い敵１体にＴＰダウ\n　ン、呪詛（必中）\n・呪詛状態の敵全体にステータスアップ解除、魔\n　法ダメージ（飛行効果無視）\n【スキル１】\n・挑発無視\n・後ろから１番目の敵と周囲に魔法ダメージ\n・後ろから１番目の敵と周囲に魔法防御力ダウン、\n　ＴＰダウン、呪い（必中）\n【通常攻撃】\n・物理か魔法攻撃力が最も高い敵１体に物理ダ\n　メージ", 410010801);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】海神の使者で、不思議な軟体の魔物。\n身体のほとんどは魔力を帯びた海水だとか。\n\n【特殊効果】\n・挑発無視\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法ダメージ\n・敵全体に物理／魔法攻撃力ダウン（必中）\n【スキル１】\n・後ろから２番目の敵を中心に魔法ダメージ\n　フィールド\n【通常攻撃】\n・後ろから２番目の敵に魔法ダメージ\n・後ろから２番目の敵と周囲に行動速度ダウン\n　（必中）", 410010901);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】神瓶に宿る魔力を操る水瓶座の魔星獣。\n激流は全てを飲込み蒼海の支配者として君臨する。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法ダメージ\n・敵全体をノックバック（必中）\n・敵全体にスタン（必中）\n・自身の魔攻が高いほど：スタン時間アップ\n【スキル１】\n・自身に物理／魔法防御力アップ\n・自身にＴＰ継続回復\n・敵全体に物理／魔法防御力ダウン\n【スキル２】\n・前から敵３体に物理ダメージ\n【バトルフィールド効果】\n・敵全体に魔法ダメージ\n・敵全体に物理／魔法防御力アップ解除\n・味方全体に物理／魔法防御力ダウン解除", 410011001);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】大きな皮翼を使い、空を駆ける翼竜。\n巨大な火球を吐き、侵入者の行く手を阻む。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から１番目の敵と周囲の敵合計４体までに物\n　理ダメージ", 410020101);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】夢うつつの狭間で惰眠を貪るナマケモノ。\n眠りを妨げると怒り狂い、超能力で暴れまわる。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法割合ダメージ\n・敵全体に物理／魔法攻撃力ダウン（必中）\n【スキル１】\n・敵全体に魔法ダメージ", 410020201);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】魔力を用いてウキキーを統べる仙猿。\n宝武具の棍を自在に操り、すべての敵をなぎ払う。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理割合ダメージ\n・対象が火傷状態：ダメージアップ\n・敵全体にスタン（必中）\n【スキル１】\n・前から敵３体に物理ダメージ\n【スキル２】\n・前から敵３体に魔法ダメージ\n・前から敵３体に火傷", 410020301);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】不安定な世界の歪みから誕生した特異個\n体の精霊。数奇な擦れ違いを端に暴走し、他の精\n霊たちを巻き込んで里に壊滅の音色を響かせる。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法割合ダメージ\n・５秒後に対象のＨＰ80％未満：沈黙（必中）\n【スキル１】\n・敵全体に魔法ダメージ\n・敵全体に物理／魔法攻撃力ダウン（必中）\n・敵全体にＨＰ吸収ダウン（必中）\n・対象のＨＰ60％未満：束縛（必中）\n【残り時間30秒で発動】\n・自身に魔法攻撃力アップ\n・自身に行動速度アップ", 410020401);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】圧倒的な魅力を放つ麗しき極彩色の艶鳥。\nその色香に囚われれば、味方を襲う下僕となる。\n\n【特殊効果】\n・全スキルダメージＴＰ回復減少\n【ユニオンバースト】\n・敵全体に魔法割合ダメージ（ＴＰ回復不可）\n・対象がバリア状態でない：誘惑\n・敵全体に物理／魔法攻撃力アップ（必中）\n【スキル１】\n・前方範囲に魔法ダメージ\n・前方範囲に誘惑（必中）\n・前方範囲に物理／魔法与ダメージダウン（必中）", 410020501);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】化け茸を統べる気高きキノコの貴族。\n幻覚性の胞子をまき散らし、敵の精神を侵食する。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・飛行効果無視\n・敵全体に物理ダメージ\n・対象のＨＰ70％未満：混乱（必中）\n【スキル１】\n・前から敵３体に物理ダメージ（召喚体無視）\n・味方全体に物理攻撃力アップ\n・味方全体に行動速度アップ\n【スキル２】\n・子分４体召喚\n・敵全体をノックバック\n・自身を中心に物理攻撃力アップフィールド、\n　物理／魔法防御力アップフィールド\n【召喚体スキル１】\n・前から敵１体に物理ダメージ\n・対象のＨＰ50％未満：ノックバック（必中）", 410020601);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】特異な力で変質したエルダーホーン。\n角に魔力を込め、打撃より強力な一撃を放つ。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・物理か魔法攻撃力が最も高い敵１体に魔法ダ\n　メージ（挑発無視）\n・このスキルの対象に物理／魔法攻撃力ダウン、\n　麻痺、継続ＴＰダウン（必中）\n【スキル１】\n・敵全体に魔法ダメージ\n・敵全体に物理／魔法攻撃力ダウン（必中）\n・自身にＴＰ回復", 410020701);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】特異な力で変質したクリーパー。\n無数のトゲを持つ蔓を巻き付け、動きを奪う。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から敵２体に物理ダメージ（召喚体無視）\n・前から敵２体に束縛（召喚体無視・必中）\n・前から敵２体にＴＰダウン（召喚体無視・必\n　中）\n・前から敵２体に最大ＨＰダウン（召喚体無視・\n　必中）\n【スキル１】\n・前から敵３体に物理防御力ダウン（召喚体無\n　視）\n・前から敵３体に毒（召喚体無視）\n・前から敵３体に物理／魔法クリダメダウン（召\n　喚体無視）", 410020801);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】紅き邪剣を尾に宿す、凶暴な大毒蛇。\n獲物を毒息で弱らせ、一撃必殺の剣で葬り去る。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・ランダムな敵１体に物理固定ダメージ\n・対象が毒状態：物理固定追加ダメージ\n・対象が猛毒状態：物理固定追加ダメージ\n・上記対象に物理／魔法攻撃力ダウン\n・敵全体にＨＰ吸収ダウン（必中）\n【スキル１】\n・敵全体に魔法ダメージ\n・対象が毒状態でない：対象に毒\n・対象が毒状態：対象に猛毒\n【通常攻撃】\n・前から敵１体に物理ダメージ\n・前から敵１体に毒", 410020901);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】大海を背負って立つ、爆走魚座の魔星獣。\n舎弟に魅せるその背中。共に往くのは覇道の極み。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体にバリア解除\n・敵全体に物理ダメージ\n・自身に行動速度アップ\n・自身に物理攻撃力アップ\n【スキル１】\n・敵全体に物理固定ダメージ\n・旗持ち子分の数が多いほど：物理固定追加ダ\n　メージ\n【スキル２】\n・前から敵２体に物理ダメージ\n・前から敵２体に物理防御力ダウン（必中）\n【スキル３】\n・旗持ち子分を３体召喚\n・自身に物理／魔法防御力ダウン解除\n【召喚体死亡時】\n・敵全体に物理／魔法攻撃力アップ\n・トルペドンに物理／魔法防御力ダウン\n【召喚体スキル１】\n・トルペドンにＴＰ回復", 410021001);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】氷河地帯を支配する厳霜の魔狼。\n冷酷な仔らが標的を貫き、氷爪が獲物を引き裂く。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n・自身への継続ダメージ量アップ\n【ユニオンバースト】\n・前から敵３体に魔法ダメージ（召喚体無視）\n・前から敵３体に凍結（召喚体無視・必中）\n・自身に物理／魔法防御力アップ", 410030101);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】はるか古に作られし防衛兵器。\n全身から放たれる光の束で侵入者を灼き尽くす。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法ダメージ（飛行効果無視）\n・敵全体に物理／魔法クリダメダウン（飛行効果\n　無視・必中）\n【スキル１】\n・前から１番目の敵と周囲に魔法ダメージ\n・前から１番目の敵と周囲に魔法防御力ダウン\n　（必中）\n【通常攻撃】\n・前から１番目の敵と周囲に魔法ダメージ", 410030201);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】過酷な環境に棲み変異した巨大トカゲ。\n硬い棘状のうろこが、敵の体力と鎧を削り落とす。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体にバリア解除\n・敵全体に物理ダメージ\n・敵全体に物理／魔法攻撃力ダウン（必中）\n・前から１番目の敵を中心に物理／魔法与ダメ\n　ダウンフィールド\n【スキル１】\n・敵全体に物理ダメージ\n・敵全体に物理防御力ダウン（必中）", 410030301);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】巨大に変異したバジリスクの亜種。異相\nの巨体を羽ばたかせ、獲物を絶望に突き落とす。\n\n【特殊効果】\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から敵１体に魔法ダメージ\n・敵全体に魔法ダメージ\n・敵全体に石化\n【スキル１】\n・敵全体に魔法ダメージ\n・敵全体に石化\n・敵全体に物理／魔法クリダメダウン（必中） \n【スキル２】\n・前から敵１体に魔法ダメージ", 410030401);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】暴食の君主に仕える、近衛の黒鉄像。\n冥府を彷徨いし魂を巧みに操り、主に捧げる。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・物理攻撃をする敵全体に火傷\n・自身の物理防御力が高いほど：ダメージアップ\n・魔法攻撃をする敵全体に火傷\n・自身の魔法防御力が高いほど：ダメージアップ\n・敵全体にＨＰ吸収ダウン\n【スキル１】\n・敵全体に魔法ダメージ（飛行効果無視）\n・敵全体をノックバック（飛行効果無視・必中）\n・前方範囲に移動速度ダウン（飛行効果無視・\n　必中）", 410030501);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】蜂の頂点に君臨する麗しき姿の支配者。\nその采配ひとつで、兵隊の奔流が獲物をのみ込む。\n\n【特殊効果】\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理固定ダメージ\n・自身の物理攻撃力が高いほど：ダメージアップ\n・敵全体に重複可能の行動速度ダウン（必中）\n・敵全体に物理／魔法クリダメダウン（必中）\n【スキル１】\n・バズナイト３体召喚\n・自身の物理攻撃力に応じてバズナイトに物理攻\n　撃力アップ\n【スキル２】\n・自身以外の味方全体に行動速度アップ\n・自身にＴＰ回復\n【召喚体特殊効果】\n・挑発／召喚体無視\n・自身に全ダメージカット\n・自身が受ける行動不能時間延長\n・全スキルダメージＴＰ回復不可\n【召喚体スキル１】\n・前から２／３／４番目の敵に物理ダメージ\n・前から２／３／４番目の敵にＴＰダウン（必中）\n・ホーネットクイーンにＴＰ回復\n・ホーネットクイーンに物理攻撃力アップ", 410030601);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】深域の力を我が物に画策する小鬼学者。\n禁忌の劇毒を創出し、全ての自由を強奪する。\n\n【特殊効果】\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体にバリア解除\n・敵全体に魔法割合ダメージ\n・敵の数が少ないほど：ダメージアップ\n【スキル１】\n・敵全体に魔法ダメージ\n・物理攻撃をする敵全体に物理攻撃力ダウン\n　（必中）\n・敵の数が少ないほど：ダウン量上昇\n・魔法攻撃をする敵全体に魔法攻撃力ダウン\n　（必中）\n・敵の数が少ないほど：ダウン量上昇\n【スキル２】\n・前から敵２体に魔法ダメージ\n・前から敵２体に麻痺／猛毒（必中）", 410030701);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】かつて人々に祀られていた三戦士の石像。\nそれぞれが能力を高め合い、必殺の一撃を放つ。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理割合ダメージ\n・自身の物理攻撃力が高いほど：ダメージアップ\n・敵全体に魔法割合ダメージ\n・自身の魔法攻撃力が高いほど：ダメージアップ\n・自身に物理／魔法攻撃力アップ\n【スキル１】\n・敵全体に物理ダメージ\n・物理攻撃をする敵全体に物理攻撃力ダウン\n　（必中）\n・自身の物理攻撃力が高いほど：ダウン量上昇\n・魔法攻撃をする敵全体に魔法攻撃力ダウン\n　（必中）\n・自身の魔法攻撃力が高いほど：ダウン量上昇\n【通常攻撃】\n・前から敵１体に物理固定ダメージ\n・自身の物理攻撃力が高いほど：ダメージアップ\n・前から敵１体に魔法固定ダメージ\n・自身の魔法攻撃力が高いほど：ダメージアップ", 410030801);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】怪力が自慢の、凶暴な一つ目巨人。\n瞳に魔力をみなぎらせ、強力な怪光線を放つ。\n\n【特殊効果】\n・飛行効果無視\n・全スキルダメージＴＰ回復減少\n【ユニオンバースト】\n・敵全体に魔法割合ダメージ（ＴＰ回復不可）\n・敵全体にＨＰ回復量ダウン（必中）\n・敵全体にＴＰダウン（必中）\n・敵全体に物理／魔法攻撃力ダウン（必中）\n【スキル１】\n・ランダムな敵１体に物理ダメージ×３回\n・このスキルの対象にスタン（必中）", 410030901);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】さらなる力を得た牡羊座の魔星獣。\n鬱々たる眠りの牢獄で冒険者の魂を貪り尽くす。\n\n【特殊効果】\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n・ＴＰ増加不可無視\n【ユニオンバースト】\n・敵全体にバリア解除\n・敵全体に魔法割合ダメージ\n・対象が行動不能状態：魔法追加ダメージ\n・対象が行動不能状態：ＴＰダウン\n【スキル１】\n・前方範囲に魔法割合ダメージ\n【スキル２】\n・残りＨＰ割合が最も低い敵１体に束縛\n　（挑発／召喚体無視）\n・対象のＨＰ70％未満：対象周囲に束縛\n【スキル３】\n・敵全体にバリア解除\n・敵全体に魔法割合ダメージ\n・敵全体に束縛\n・対象のＨＰ70％未満：束縛時間アップ\n【スキル４】\n・敵全体にバリア解除\n・敵全体に魔法割合ダメージ \n・敵全体にＨＰ回復量ダウン（必中）\n・敵全体にＨＰ吸収ダウン（必中）\n・敵全体に物理／魔法クリダメダウン（必中） ", 410031001);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】武具に取り憑き、手足のように操る魔物。\n堅牢な装甲と巨大な魔剣で冒険者を苦しめる。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から敵１体に魔法ダメージ\n・前から敵１体にスタン（必中）\n・自身に魔法攻撃力アップ\n・自身に物理防御力アップ\n【スキル１】\n・前から敵１体に魔法ダメージ\n・前から敵１体にスタン（必中）\n・前から敵１体にＨＰ回復量ダウン（必中）", 410040101);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】死してなお強敵を求め続けるタフガイ。\n生前の腕力と死後の霊力を駆使し相手を圧倒する。\n\n【特殊効果】\n・飛行効果無視\n・自身への継続ダメージ量アップ\n・自身の弱体効果数が多いほど：自身の被ダメー\n　ジアップ\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理割合ダメージ\n・自身の物理攻撃力が高いほど：ダメージアップ\n・敵全体に魔法割合ダメージ\n・自身の魔法攻撃力が高いほど：ダメージアップ\n【スキル１】\n・自身に物理／魔法攻撃力アップ\n・自身が継続ダメージ状態ではない：自身に\n　物理／魔法防御力アップ\n【通常攻撃】\n・前から敵１体に物理／魔法ダメージ\n【部位ブレイク効果】\n・部位１ブレイク：物理／魔法攻撃力ダウン\n・部位２ブレイク：物理／魔法攻撃力ダウン\n・部位３ブレイク：物理／魔法攻撃力ダウン", 410040201);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】砂地にのさばる獰猛な大怪鳥。紫電を\n纏い嵐を巻き起こすさまは、天災と恐れられる。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法ダメージ\n・敵全体に魔法防御力ダウン（必中）\n【スキル１】\n・前から敵２体に物理ダメージ\n・前から敵２体にスタン（必中）\n【スキル２】\n・前から敵２体に物理ダメージ\n・前から敵２体に物理防御力ダウン（必中）", 410040301);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】人竜一体となって戦うゴブリン騎手。\n敏速に空を駆け巡り、地上の敵に襲いかかる。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・後ろから敵３体に物理ダメージ\n・後ろから敵３体にスタン（必中）\n【スキル１】\n・後ろから敵２体に物理ダメージ\n・後ろから敵２体に物理防御力ダウン（必中）\n・後ろから敵２体にＴＰダウン（必中）\n・後ろから敵２体にＴＰ上昇ダウン（必中）\n【通常攻撃】\n・後ろから敵１体に物理ダメージ（挑発無視）", 410040401);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】戦空を駆け舞う、天上の戦乙女。\n目にも留まらぬ連射で、敵の進行を射止める。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前方範囲の敵４体に物理ダメージ\n・前方範囲の敵４体にＴＰダウン（必中）\n・前方範囲の敵４体にＴＰ上昇ダウン（必中）\n・前方範囲の敵４体に行動速度ダウン（必中）\n【スキル１】\n・前から敵４体に物理ダメージ\n・前から敵４体に物理／魔法攻撃力ダウン（必\n　中）\n・自身に行動速度アップ", 410040501);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】甲羅に大樹が根ざすほどの老大な陸ガメ。\n敵の攻撃を耐え続け、憤怒の反撃を見舞う。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理ダメージ\n・敵全体に物理／魔法クリダメダウン（必中）\n【スキル１】\n・自身に物理／魔法防御力アップ\n・敵全体に物理固定ダメージ（飛行効果無視）\n・自身の物理攻撃力が高いほど：ダメージアップ\n【全ターゲットブレイク時発動】\n・自身に被クリダメアップ\n・自身にブレイク無効", 410040601);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】鋭い眼つきで、獲物と波を探し求める海\nのハンター。魔力で無限に生み出す潮水は敵の刃\nと気力を鈍らせる。\n\n【特殊効果】\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体にバリア解除\n・敵全体に物理割合ダメージ\n・敵の数が少ないほど：ダメージアップ\n【スキル１】\n・敵全体に物理ダメージ\n・敵全体にＴＰダウン（必中）\n・敵の数が少ないほど：ダウン量上昇\n・敵全体にＴＰ上昇ダウン（必中）\n・敵の数が少ないほど：ダウン量上昇\n【スキル２】\n・前から敵２体に物理ダメージ\n・前から敵２体に物理／魔法クリティカルダメー\n　ジダウン（必中）", 410040701);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】棄てられたモノの怨念より生まれた悪霊。\n怨む者の心臓を狙い定め、呪いの釘を打ち込む。\n\n【特殊効果】\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法ダメージ\n・敵全体に物理／魔法攻撃力ダウン（必中）\n・敵全体にＨＰ回復量ダウン（必中）\n【スキル１】\n・敵全体に魔法ダメージ\n・敵全体に呪い（必中）\n・敵全体に束縛（必中）\n・最もＨＰ割合が低い敵のＨＰ割合が低いほど：\n　束縛時間アップ\n【スキル２】\n・物理か魔法攻撃力が最も高い敵１体に魔法ダ\n　メージ\n・物理か魔法攻撃力が最も高い敵１体に物理／\n　魔法与ダメージダウン、呪詛（必中）", 410040801);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】大地に穿たれし禍穴より現れた、災いを\nもたらす巨竜。放たれる猛炎は万象を焼き尽くし、\n愚かなる冒険者の覚悟を、希望を灰燼へと帰す。\n\n【特殊効果】\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理／魔法ダメージ\n・前から１番目の敵を中心に物理／魔法ダメージ\n　フィールド\n【スキル１】\n・前から敵１体に物理／魔法ダメージ\n【スキル２】\n・敵全体に物理／魔法防御力ダウン\n・敵全体にＨＰ吸収ダウン\n・対象のＨＰが60％未満：物理／魔法攻撃力ダ\n　ウン、重複可能の行動速度ダウン\n【ＨＰ40％以下時発動】\n・自身にＴＰダウンカット\n・自身に物理／魔法攻撃力アップ\n・自身に重複可能の行動速度アップ\n・自身に物理／魔法防御力ダウン", 410040901);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】さらなる力を得た牡牛座の魔星獣。\n力の限界を超えた戦斧の一撃が全てを破砕する。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理割合ダメージ\n・自身の物理攻撃力が高いほど：ダメージアップ\n・敵全体に火傷（必中）\n【スキル１】\n・前から敵１体に物理ダメージ\n・前から敵１体をノックバック（必中）\n・前から敵１体にスタン（必中）\n・自身に物理攻撃力アップ\n・対象のＨＰ割合が低いほど：アップ量上昇\n【スキル２】\n・敵全体に魔法ダメージ\n・敵全体に物理／魔法クリティカルダウン（必中）\n・敵全体に麻痺（必中）\n【スキル３】\n・前から敵２体に物理ダメージ（召喚体無視）\n・前から敵２体にスタン（召喚体無視・必中）\n・自身に物理攻撃力アップ\n・対象のＨＰ割合が低いほど：アップ量上昇\n【スキル４】\n・飛行効果無視\n・敵味方全体に物理／魔法攻撃力アップ\n・敵味方全体に物理／魔法防御力ダウン\n・敵味方全体に行動速度アップ\n・自身にＴＰ継続回復", 410041001);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】ルナの魔力の結晶でその身を覆う巨大\nゴーレム。身に纏う結晶は堅牢な盾であり、全\nてを穿つ矛となる。\n\n【特殊効果】\n・継続ダメージ状態になった時：自身に行動速度\n　ダウン\n【ユニオンバースト】\n・自身にステータスダウン解除\n・自身に物理／魔法防御力アップ\n【スキル１】\n・敵全体に物理ダメージ\n・敵全体にスタン\n【スキル２】\n・前方範囲に物理ダメージ\n・自身にＴＰ回復\n・自身に物理／魔法攻撃力アップ\n【ＨＰ40％以下時発動】\n・自身に物理攻撃力アップ\n・自身に行動速度アップ\n・行動パターン変化", 410050101);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】過酷な環境で進化したプチグリフォン。\n竜巻で獲物を巻き上げ、空で狩りをする。\n\n【特殊効果】\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から敵５体に魔法ダメージ\n・前から敵５体をノックバック（必中）\n・前から敵５体にスタン（必中）", 410050201);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】魔力を蓄え雷撃として放電する怪鳥。\n雷雲と共に顕現し、天災の如き雷で敵を葬り去る。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から敵１体に魔法ダメージ\n・自身に魔法攻撃力アップ\n・自身に魔法防御力アップ", 410050301);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】遠吠えで獲物をひるませツメで引き裂く。\n自身の欲望のまま、残虐の限りを尽くす魔狼。\n\n【特殊効果】\n・全スキルダメージＴＰ回復減少\n【ユニオンバースト】\n・ランダムな敵３体にステータスアップ解除\n・このスキルの対象に物理ダメージ\n【スキル１】\n・敵全体に物理／魔法攻撃力ダウン\n・自身に行動速度アップ", 410050401);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】氷河地帯を支配する厳霜の魔狼。\n冷酷な仔らが標的を貫き、氷爪が獲物を引き裂く。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n・自身への継続ダメージ量アップ\n【ユニオンバースト】\n・前から敵３体に魔法ダメージ（召喚体無視）\n・前から敵３体に凍結（召喚体無視・必中）\n・自身に物理／魔法防御力アップ\n【スキル１】\n・前から敵３体に魔法ダメージ（召喚体無視）\n・前から敵３体に魔法防御力ダウン（召喚体無視・\n　必中）", 410050501);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】強者の魂を幽鬼とし従える、冥府の高官。\n亡者の念が刃に絡みつき、動きを鈍らせる。\n\n【特殊効果】\n・全スキルダメージＴＰ回復減少\n【ユニオンバースト】\n・前から１番目の敵と周囲に魔法割合ダメージ\n・自身の魔法攻撃力が高いほど：ダメージアップ\n・前から１番目の敵と周囲に最大ＨＰダウン\n　（必中）\n・与えた総ダメージが高いほど：ＨＰダウン量\n　上昇\n【スキル１】\n・前から１番目の敵と周囲に呪い（ＴＰ回復不可）\n・自身の魔法攻撃力が高いほど：ダメージアップ\n・前から１番目の敵と周囲にＨＰ回復量ダウン\n・前から１番目の敵と周囲にＨＰ吸収ダウン\n【通常攻撃】\n・前から敵１体に魔法割合ダメージ\n・自身の魔法攻撃力が高いほど：ダメージアップ", 410050601);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】特異な力で変質したオークリーダー。\n巨大な盾で、攻防一体の一撃を繰り出す。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から敵３体に物理固定ダメージ（召喚体無視）\n・自身の物理攻撃力が高いほど：ダメージアップ\n・前から敵３体にスタン（召喚体無視・必中）\n【スキル１】\n・自身に行動速度アップ\n・自身に全ダメージカット\n・自身の魔法攻撃力が高いほど：カット量アップ\n・自身にＴＰ回復\n・前から敵２体にＴＰダウン（召喚体無視）\n・前から敵２体にＨＰ吸収ダウン（召喚体無視）", 410050701);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】魔力を宿せし黒曜の結晶竜。美しい体躯\nの輝きは冥府を彷徨いし魂の嘆きといわれている。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に魔法割合ダメージ\n・敵全体にＴＰダウン（必中）\n【スキル１】\n・敵全体にＨＰ吸収ダウン\n・敵全体に物理防御力ダウン\n【スキル２】\n・物理か魔法攻撃力が最も高い敵１体に物理ダ\n　メージ\n・このスキルの対象と周囲に物理ダメージ\n・このスキルの対象と周囲にＴＰダウン（必中）", 410050801);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【魔法】巨大に変異したバジリスクの亜種。異相\nの巨体を羽ばたかせ、獲物を絶望に突き落とす。\n\n【特殊効果】\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・前から敵１体に魔法ダメージ\n・敵全体に魔法ダメージ\n・敵全体に石化\n【スキル１】\n・敵全体に魔法ダメージ\n・敵全体に石化\n・敵全体に物理／魔法クリダメダウン（必中）\n【スキル２】\n・前から敵１体に魔法ダメージ", 410050901);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】さらなる力を得た双子座の魔星獣。\n前衛で防御しつつ、熟達した技で攻撃を行う。\n\n【特殊効果】\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体に物理割合ダメージ（飛行効果無視）\n・前から１番目の敵を中心に物理／魔法攻撃力ダ\n　ウンフィールド\n・前から１番目の敵を中心に物理／魔法クリティ\n　カルダウンフィールド\n【スキル１】\n・後方範囲の敵２体に物理ダメージ（召喚体無視）\n・後方範囲の敵２体にスタン（召喚体無視・必中）\n【スキル２】\n・後方範囲の敵２体に物理ダメージ（召喚体無視）\n・後方範囲の敵２体にＴＰダウン（召喚体無視・\n　必中）\n・左側のツインピッグスが前方へ移動する\n【スキル３】\n・敵全体に物理ダメージ\n・自身にＴＰ回復\n・自身に行動速度アップ\n【スキル４】\n・敵全体に重複可能の行動速度ダウン\n・敵全体に物理／魔法与ダメージダウン", 410051001);
INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】ルナの魔力で目覚めた、巨腕の改造人間。\n小型リアクターの最大出力は自身が感電するほど。\n\n【ユニオンバースト】\n・前から敵３体に物理ダメージ\n・前から敵２体に麻痺（必中）\n・自身にステータスアップ解除\n・自身に物理／魔法防御力ダウン\n【スキル１】\n・敵全体に魔法ダメージ\n・自身に物理攻撃力アップ\n【スキル２】\n・味方全体に行動速度アップ\n【スキル３】\n・前から敵２体に物理ダメージ\n【ＨＰ40％未満時発動】\n・自身に行動速度アップ\n・自身に物理攻撃力アップ", 502016103);
