INSERT INTO `v1_837f4ebc555baf535a19f79a3716ced7d4359738b17273561e3eed89b8312610` VALUES ("【物理】ルナの魔力の結晶でその身を覆う巨大\nゴーレム。身に纏う結晶は堅牢な盾であり、全\nてを穿つ矛となる。\n\n【特殊効果】\n・継続ダメージ状態になった時：自身に行動速度\n　ダウン\n【ユニオンバースト】\n・自身にステータスダウン解除\n・自身に物理／魔法防御力アップ\n・自身以外の味方全体に物理／魔法防御力アップ\n【スキル１】\n・敵全体に物理ダメージ\n・敵全体にスタン\n【スキル２】\n・前方範囲に物理ダメージ\n・自身にＴＰ回復\n・味方全体に物理／魔法攻撃力アップ\n【ＨＰ40％以下時発動】\n・自身に物理攻撃力アップ\n・自身に行動速度アップ\n・行動パターン変化", 502017408);
